#include<bits/stdc++.h>
using namespace std;
int root[1000010],v[1000010];
struct segment_tree
{
    struct node
    {
        int l,r,val;
        int lson,rson;
        int tag;
        node():tag(0){}
    }a[25000010];
    int cnt;
    segment_tree():cnt(0){}
    int init(int l,int r)
    {
        int x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].val=l;
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        return x;
    }
    int update(int x,int p,int v)
    {
        int now=++cnt;
        a[now]=a[x];
        if(a[x].l==a[x].r)
        {
            a[now].val=v;
            return now;
        }
        int mid=(a[x].l+a[x].r)>>1;
        if(p<=mid)
        {
            a[now].lson=update(a[x].lson,p,v);
        }
        else
        {
            a[now].rson=update(a[x].rson,p,v);
        }
        return now;
    }
    int getval(int x,int p)
    {
        if(a[x].l==a[x].r)
        {
            return a[x].val;
        }
        int mid=(a[x].l+a[x].r)>>1;
        if(p<=mid)
        {
            return getval(a[x].lson,p);
        }
        else
        {
            return getval(a[x].rson,p);
        }
    }
}fa;
int find(int ver,int x)
{
    int now=fa.getval(root[ver],x);
    if(now==x)
    {
        return x;
    }
    int ans=find(ver,now);
    root[ver]=fa.update(root[ver],x,ans);
    return ans;
}
void merge(int ver,int x,int y)
{
    int a=find(ver,x),b=find(ver,y);
    if(a==b)
    {
        return;
    }
    if(v[a]>v[b])
    {
        root[ver]=fa.update(root[ver],b,a);
    }
    else
    {
        if(v[a]==v[b])
        {
            v[b]++;
        }
        root[ver]=fa.update(root[ver],a,b);
    }
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    root[0]=fa.init(1,n);
    for(int i=1;i<=m;i++)
    {
        int op,x,y;
        scanf("%d%d",&op,&x);
        if(op==1)
        {
            scanf("%d",&y);
            root[i]=root[i-1];
            merge(i,x,y);
        }
        else if(op==2)
        {
            root[i]=root[x];
        }
        else
        {
            scanf("%d",&y);
            root[i]=root[i-1];
            if(find(i,x)==find(i,y))
            {
                printf("1\n");
            }
            else
            {
                printf("0\n");
            }
        }
    }
    return 0;
}
